fn for_each_console_byte_for_sbi(bytes: &[u8], mut emit: impl FnMut(u8)) {
    let mut idx = 0;
    while idx < bytes.len() {
        if bytes[idx] == b'\r' && bytes.get(idx + 1) == Some(&b'\n') {
            emit(b'\n');
            idx += 2;
            continue;
        }
        emit(bytes[idx]);
        idx += 1;
    }
}

